INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00113', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於第三審訴訟程序，下列敘述何者正確？', '["第二審判決包含財產權請求及非財產權請求，如財產權請求之上訴所得受之利益未逾新臺幣150萬 元，僅得就非財產權請求部分提起第三審上訴", "上訴人以原判決違背法令為上訴理由，未於上訴狀記載原判決所違背之法令及其具體內容者，其上 訴為不合法", "上訴第三審法院，非以原判決違背法令為理由，並經第三審法院許可者，不得為之", "對於第二審判決提起第三審上訴，上訴人未委任律師為其訴訟代理人者，其上訴均為不合法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00114', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '不得上訴於第三審法院之事件，其第二審法院所為裁定，不得抗告。但下列裁定，何者得向原法院提 出異議？', '["確定當事人應負擔訴訟費用額之裁定", "選任特別代理人之裁定", "駁回拒絕證言之裁定", "對於拒卻鑑定人之聲明所為之裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00115', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '當事人於上訴期間內提起合法之上訴，於上訴期間屆滿後撤回上訴，如他造未提起上訴或附帶上訴， 應自何時起算再審期間？', '["原判決送達時", "上訴期間屆滿時", "撤回上訴時", "被上訴人同意上訴人撤回上訴時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00116', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於當事人書狀，下列敘述何者正確？', '["當事人得法院許可者，可先以電信傳真將書狀傳送於法院，再依法院裁定補正紙本書狀", "當事人或代理人應於書狀內簽名或蓋章，不得以指印代簽名", "當事人於書狀內引用所執之文書，並已添具該文書之影本，則無須同時添具原本", "書狀及其附屬文件，除提出於法院者外，不須提出繕本或影本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00117', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於假扣押、假處分，下列敘述何者正確？', '["債權人就得易為金錢之請求，欲保全強制執行，應聲請假處分", "債權人就附條件之金錢請求，得聲請假扣押", "本案訴訟雖已繫屬於第二審，假扣押之聲請，仍應由本案原繫屬之第一審法院為管轄權法院", "法院酌定假處分之方法，應受債權人聲明之拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00118', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於宣告證券無效之公示催告及除權判決程序，下列敘述何者錯誤？', '["公示催告，應記載持有證券人應於期間內申報權利及提出證券，並曉示以如不申報及提出者，即宣 告證券無效", "除權判決，應宣告證券無效", "除權判決之要旨，法院應依職權公告於法院公告處，並公告於法院網站；認為必要時，得命登載於 公報或新聞紙；如法院所在地有交易所者，並應黏貼於該交易所", "因除權判決而為清償者，於除權判決撤銷後，均不得以其清償對抗債權人或第三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00119', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲男與乙女婚後生有一子丙，後乙女以甲男為被告向法院提起撤銷婚姻之訴，合併請求甲給付剩餘財 產分配新臺幣100萬元，並一併請求酌定未成年人丙由乙任親權人。若第一審法院判決乙之上述請求 均有理由。下列敘述何者錯誤？', '["若甲就撤銷婚姻、剩餘財產分配與親權酌定均不服，適用上訴程序", "若甲僅就親權酌定不服，適用抗告程序", "若甲僅就撤銷婚姻不服，剩餘財產分配與親權酌定之裁判歸於確定", "若甲主張乙有構成離婚事由之情事，甲就撤銷婚姻提起上訴後，得合併提起離婚之反訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00120', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於聲請監護宣告事件及撤銷監護宣告事件，下列敘述何者錯誤？', '["專屬應受監護宣告之人或受監護宣告之人住所地或居所地法院管轄", "應受監護宣告之人及受監護宣告之人有程序能力", "監護宣告之裁定生效後，經抗告法院認抗告有理由而廢棄；受監護宣告之人於該裁定經廢棄確定前 所為之行為得主張歸於無效", "法院對於撤銷監護宣告之聲請，認受監護宣告者受監護原因消滅，而仍有輔助之必要者，得依聲請 或依職權以裁定變更為輔助之宣告 乙、刑事訴訟法部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00121', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲被起訴犯竊盜罪嫌，下列何種情形，不屬於相牽連案件？', '["犯與本罪有關係之藏匿人犯", "犯與本罪有關係之湮滅證據", "犯與本罪有關係之侵占罪", "犯與本罪有關係之偽證罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00122', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '同一案件繫屬於有管轄權之數法院者，原則上由何法院審判？', '["繫屬在先之法院", "繫屬在後之法院", "直接上級法院", "最高法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
